before_code:
module ram_unit(
  input [3:0] address,
  input write_enable,
  input [15:0] write_data,
  output [15:0] read_data
);
  reg [15:0] memory [15:0];

  assign read_data = memory[address];

  always @(*) begin
    if (write_enable) memory[address] <= write_data;
  end
endmodule

