  wire [15:0] data_bus;
  wire [3:0] addr_bus;

  ram_unit mem(.address(addr_bus), .write_enable(wen), .write_data(data_bus), .read_data(data_bus), .extra_signal(1'b0));

  assign output_data = data_bus;
endmodule

